import React from "react";
import {Bar} from 'react-chartjs-2';

const Chart = (props) => {
    const data = {
        labels: props.database.labels,
        datasets: [{
            label: 'My First Dataset',
            data: props.database.data,
            backgroundColor: [
                'rgb(255, 99, 132)',
                'rgb(75, 192, 192)',
                'rgb(255, 205, 86)',
                'rgb(201, 203, 207)',
                'rgb(54, 162, 235)',
                'rgb(37, 203, 37)',
                'rgb(250, 128, 114)',
                'rgb(127, 255, 212)',
                'rgb(30, 144, 255)',
                'rgb(255, 140, 0)',
                'rgb(255, 0, 255)',
                'rgb(0, 255, 255)',
                'rgb(218, 165, 32)',
                'rgb(37, 203, 37)',
                'rgb(37, 203, 37)',
                'rgb(245, 222, 179)',
            ]
        }]
    };

    return <React.Fragment>
       <div className="chart-wrapper">
           <Bar
               data={data}
               width={100}
               height={50}
               options={{
                   maintainAspectRatio: true
               }}
           />
       </div>
    </React.Fragment>
}

export default Chart;
